const canvas = document.createElement('canvas');
const ctx = canvas.getContext('2d');
document.body.style.margin = '0';
document.body.style.overflow = 'hidden';
document.body.style.background = '#111';
document.body.appendChild(canvas);

let W = window.innerWidth;
let H = window.innerHeight;
canvas.width = W;
canvas.height = H;

window.addEventListener('resize', () => {
  W = window.innerWidth;
  H = window.innerHeight;
  canvas.width = W;
  canvas.height = H;
});

const keys = Object.create(null);

window.addEventListener('keydown', (e) => {
  keys[e.key.toLowerCase()] = true;
});

window.addEventListener('keyup', (e) => {
  keys[e.key.toLowerCase()] = false;
});

const track = {
  x: 80,
  y: 80,
  w: 1200,
  h: 700
};

const player = {
  x: track.x + 120,
  y: track.y + track.h / 2,
  r: 18,
  angle: 0,
  speed: 0,
  maxSpeed: 520,
  accel: 900,
  brake: 1200,
  friction: 600,
  turnRate: 3.2,
  distance: 0
};

let lastFrame = Date.now();
let elapsedMs = 0;

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function update(dt) {
  const dtSec = dt / 1000;

  const accelerating = !!keys['w'] || !!keys['arrowup'];
  const braking = !!keys['s'] || !!keys['arrowdown'];
  const left = !!keys['a'] || !!keys['arrowleft'];
  const right = !!keys['d'] || !!keys['arrowright'];

  if (accelerating) {
    player.speed += player.accel * dtSec;
  } else if (braking) {
    player.speed -= player.brake * dtSec;
  } else {
    if (player.speed > 0) {
      player.speed = Math.max(0, player.speed - player.friction * dtSec);
    } else if (player.speed < 0) {
      player.speed = Math.min(0, player.speed + player.friction * dtSec);
    }
  }

  player.speed = clamp(player.speed, -player.maxSpeed * 0.45, player.maxSpeed);

  const turnFactor = Math.min(1, Math.abs(player.speed) / player.maxSpeed);
  if (left) player.angle -= player.turnRate * turnFactor * dtSec;
  if (right) player.angle += player.turnRate * turnFactor * dtSec;

  const dx = Math.cos(player.angle) * player.speed * dtSec;
  const dy = Math.sin(player.angle) * player.speed * dtSec;

  player.x += dx;
  player.y += dy;
  player.distance += Math.hypot(dx, dy);

  const minX = track.x + player.r;
  const maxX = track.x + track.w - player.r;
  const minY = track.y + player.r;
  const maxY = track.y + track.h - player.r;

  if (player.x < minX) {
    player.x = minX;
    player.speed *= -0.25;
  }
  if (player.x > maxX) {
    player.x = maxX;
    player.speed *= -0.25;
  }
  if (player.y < minY) {
    player.y = minY;
    player.speed *= -0.25;
  }
  if (player.y > maxY) {
    player.y = maxY;
    player.speed *= -0.25;
  }

  elapsedMs += dt;
}

function drawTrack() {
  ctx.fillStyle = '#2a2f36';
  ctx.fillRect(0, 0, W, H);

  ctx.fillStyle = '#3a3f48';
  ctx.fillRect(track.x, track.y, track.w, track.h);

  ctx.strokeStyle = '#d9d9d9';
  ctx.lineWidth = 6;
  ctx.strokeRect(track.x, track.y, track.w, track.h);

  ctx.setLineDash([24, 18]);
  ctx.strokeStyle = '#f2c94c';
  ctx.lineWidth = 4;
  ctx.strokeRect(track.x + 20, track.y + 20, track.w - 40, track.h - 40);
  ctx.setLineDash([]);

  ctx.fillStyle = '#111';
  ctx.fillRect(track.x + 20, track.y + 20, 14, track.h - 40);
  ctx.fillRect(track.x + track.w - 34, track.y + 20, 14, track.h - 40);
  ctx.fillRect(track.x + 20, track.y + 20, track.w - 40, 14);
  ctx.fillRect(track.x + 20, track.y + track.h - 34, track.w - 40, 14);

  ctx.fillStyle = '#222';
  ctx.fillRect(track.x + 40, track.y + 40, track.w - 80, track.h - 80);
}

function drawPlayer() {
  ctx.save();
  ctx.translate(player.x, player.y);
  ctx.rotate(player.angle);

  ctx.fillStyle = '#ff4d4d';
  ctx.beginPath();
  ctx.moveTo(player.r + 10, 0);
  ctx.lineTo(-player.r, -player.r * 0.75);
  ctx.lineTo(-player.r * 0.6, 0);
  ctx.lineTo(-player.r, player.r * 0.75);
  ctx.closePath();
  ctx.fill();

  ctx.fillStyle = '#fff';
  ctx.beginPath();
  ctx.arc(4, -6, 4, 0, Math.PI * 2);
  ctx.arc(4, 6, 4, 0, Math.PI * 2);
  ctx.fill();

  ctx.restore();
}

function drawHUD() {
  ctx.fillStyle = 'rgba(0,0,0,0.55)';
  ctx.fillRect(20, 20, 280, 108);

  ctx.fillStyle = '#fff';
  ctx.font = '18px sans-serif';
  ctx.fillText('WASD / Arrow Keys to drive', 34, 50);
  ctx.fillText('Speed: ' + Math.round(player.speed) + ' px/s', 34, 76);
  ctx.fillText('Distance: ' + Math.round(player.distance) + ' px', 34, 102);
}

function frame() {
  const now = Date.now();
  const dt = now - lastFrame;
  lastFrame = now;

  update(dt);

  drawTrack();
  drawPlayer();
  drawHUD();
}

setInterval(frame, 16);